<template>
	<view>
		<view class="header">
			<view class="headerBox"
				:style="{ 'padding-top':  `${statusBarHeight}px`, 'height': `calc( ${statusBarHeight}px + 48px);`, 'background-color': background}">
				<slot name="header">
				</slot>
			</view>
			<view class="headerBottom" :style="{ 'padding-bottom': paddingBottom }"></view>
		</view>
	</view>
</template>

<script>
	import {
		mapGetters
	} from 'vuex'
	export default {
		name: "my-page-header",
		props: {
			background: {
				type: String,
				default: "#FFFFFF",
			},
			noPaddingBottom: {
				type: Boolean,
				default: false,
			},
		},
		data() {
			return {
				// header高度统一为48px
				// headerHeight:'48px',
				statusBarHeight: 44
			};
		},
		computed: {
			...mapGetters(['deviceInfo']),
			paddingBottom() {
				if (this.noPaddingBottom)
					return `${this.statusBarHeight}px`
				else
					return `calc(${this.statusBarHeight}px + 48px)`
			},
		},
		mounted() {
			
		},
		beforeCreate() {
					
		},
		created() {			
			this.statusBarHeight = this.deviceInfo.top
		},
		methods: {

		}
	}
</script>

<style lang="scss" scoped scoped>
	.header {
		.headerBox {
			width: 100%;
			position: fixed;
			top: 0;
			left: 0;
			z-index: 99;
			// padding-top: var(--status-bar-height);
			// height: calc(var(--status-bar-height) + 48px);
			background-color: #FFFFFF;
		}

		.headerBottom {
			// padding-bottom: calc(var(--status-bar-height) + 48px);
		}
	}
</style>