<template>
	<view>
		<!-- #ifdef MP -->
		<my-page-header>
			<view slot="header">
				<view class="header-wrap">消息</view>
			</view>
		</my-page-header>
		<!-- #endif -->
		<!-- #ifdef H5 -->
		<status-bar />
		<!-- #endif -->
		<!-- #ifdef APP -->
		<status-bar />
		<!-- #endif -->
		<view class="news">
			<view class="new-system-box">
				<view class="item" :key="index" v-for="(item,index) in list" @click="clickFun(goDetail,item)">
					<view class="image">
						<image class="icon" :src="item.img" mode="aspectFit"></image>
						<u-tag :text="item.num>99 ?'99+':item.num" class="img-tag" shape="circle" size="mini"
							:closeable="false" type="error" mode="dark" :show="item.num>0" />
					</view>
					<view class="right">
						<view class="title">{{item.title}}
							<text class="time">
								{{ item.time>0?$util.timeFormat(item.time,'yyyy-mm-dd hh:MM:ss'):'' }}
							</text>
						</view>
						<view class="news-content line1">
							{{item.desc}}
						</view>
					</view>
				</view>
			</view>

			<u-popup v-model="showLoginBox" mode="bottom" z-index="99999" height="524" class="subscribePup"
				:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20">
				<view class="loginBox">
					<image class="img" :src="$util.img('/statics/uni/img/index/loginPopupImg.png')" mode="aspectFit">
					</image>
					<view class="loginBtn" @click="clickBoxLogin">
						微信一键登录
					</view>
					<text class="text"></text>
				</view>
			</u-popup>
		</view>
		<u-tabbar :height="110" active-color='#f06c7a' inactive-color="#606266" :list="tabBarList"></u-tabbar>
	</view>
</template>

<script>
	import {
		mapActions
	} from 'vuex'
	import MyPageHeader from '@/components/my-page-header'
	import StatusBr from '@/components/my-page-header/status-bar'
	export default {
		components: {
			'my-page-header': MyPageHeader,
			'status-bar': StatusBr,
		},
		data() {
			return {
				showLoginBox: false,
				sys: this.$util.sys(),
				activeColor: '#f06c7a',
				inactiveColor: '#606266',
				list: [],
				wxxcx_code: '',
			};
		},
		onLoad(e) {


			//#ifdef H5

			if (!this.userinfo.isLogin && this.$util.browserType('weixin')) {
				if (e.thirdlogin_type) {

					//是否第三方登录
					if (e.thirdlogin_type == 'weixin') {
						this.thirdLogin(e.thirdlogin_type)
					}

				} else {

					this.loadData();
					//直接登录
					// this.$u.api.getWxgzhLoginUrl({
					// 	pid: uni.getStorageSync('pid'),
					// 	type: 2,
					// 	uri: location.href
					// }).then((res) => {

					// 	location.href = res.url
					// })
				}



			} else {

				this.loadData();
			}

			//#endif
			// #ifndef H5
			this.loadData();
			// #endif


		},
		onShow() {

		},
		methods: {
			//#ifdef MP-WEIXIN
			//请求微信接口，用来获取code
			wxxcxLogin() {
				var that = this
				uni.login({
					provider: 'weixin',
					success: function(loginRes) {
						that.wxxcx_code = loginRes.code

					}
				});

				if (uni.getUserProfile) {
					uni.getUserProfile({
						desc: '用于完善会员资料',
						success: (res) => {

							that.$u.api.login({
									code: that.wxxcx_code,
									encryptedData: res.encryptedData,
									iv: res.iv,
									login_type: 3,
								})
								.then(res => {
									res.userinfo.isLogin = true
									res.userinfo.token = res.token
									uni.setStorageSync('token', res.token)
									this.$u.vuex('userinfo', res.userinfo);
									uni.hideLoading()

									this.$util.msg('登录成功');

									let pid = uni.getStorageSync('pid')
									if (pid) {
										this.$u.api.bindPid({
											pid: uni.getStorageSync('pid')
										})
									}
									this.showLoginBox = false
									this.loadData()

								}).catch(err => {})
						}
					})

				} else {
					uni.getUserInfo({
						success: function(res) {
							that.$u.api.login({
									code: that.wxxcx_code,
									encryptedData: res.encryptedData,
									iv: res.iv,
									login_type: 3,
								})
								.then(res => {

									res.userinfo.isLogin = true
									res.userinfo.token = res.token
									uni.setStorageSync('token', res.token)
									this.$u.vuex('userinfo', res.userinfo);
									uni.hideLoading()

									this.$util.msg('登录成功');

									let pid = uni.getStorageSync('pid')
									if (pid) {
										this.$u.api.bindPid({
											pid: uni.getStorageSync('pid')
										})
									}
									this.showLoginBox = false
									this.loadData()

								}).catch(err => {})

						}
					})

				}
			},
			//#endif

			clickBoxLogin() {
				// #ifdef H5
				//直接登录
				this.$u.api.getWxgzhLoginUrl({
					pid: uni.getStorageSync('pid'),
					type: 2,
					uri: location.href
				}).then((res) => {

					location.href = res.url
				})
				// #endif
				//#ifdef MP-WEIXIN
				this.wxxcxLogin()
				// #endif
			},

			clickFun(func, item) {

				if (!this.userinfo.isLogin) {
					// #ifdef H5
					if (this.$util.browserType('weixin')) {
						this.showLoginBox = true;
						return;
					}
					// #endif

					// #ifdef MP-WEIXIN
					this.showLoginBox = true;
					return;
					// #endif


				}


				typeof func === 'function' && func(item)
				if (typeof func === 'string') {
					this.$util.on(func)
				}
			},
			//#ifdef H5
			thirdLogin(thirdlogin_type) {


				this.$u.api.thirdLogin({
						type: thirdlogin_type
					})
					.then(res => {

						if (typeof res == 'object') {
							//存储token和用户信息

							res.userinfo.isLogin = true
							res.userinfo.token = res.token

							this.userinfo = res.userinfo
							uni.setStorageSync('token', res.token)
							this.$u.vuex('userinfo', res.userinfo);

							this.$util.msg('登录成功');

							let pid = uni.getStorageSync('pid')
							if (pid) {
								this.$u.api.bindPid({
									pid: uni.getStorageSync('pid')
								})
							}

							this.loadData()
						}


					}).catch(res => {

					})

			},
			//#endif
			loadData() {
				this.$u.api.notice({})
					.then(res => {
						this.list = res
					}).catch(res => {})
			},
			//消息详情
			goDetail(item) {

				switch (item.type) {
					case 1: //跳转地址
						this.$util.on(item.url);
						break;
				}


			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	page {
		background-color: #fff;
	}

	.header-wrap {
		height: 88rpx;
		line-height: 88rpx;
		text-align: center;
		font-weight: bold;
		border-bottom: 1px solid #f5f5f5;
	}

	.news {
		width: 100%;
		// height: calc(100vh - 140rpx);
		background-color: #fff;
		display: flex;
		align-items: center;
		justify-content: flex-start;
		flex-direction: column;
	}

	.news .new-system-box {
		width: 100%;
		padding: 20rpx;
		display: flex;
		align-items: center;
		justify-content: flex-start;
		flex-direction: column;
		gap: 40rpx;
	}

	.news .new-system-box .item {
		width: 100%;
		display: flex;
		align-items: center;
		justify-content: flex-start;
		gap: 8rpx;
		height: 114rpx;
	}

	.news .new-system-box .item .image {
		width: 112rpx;
		height: 112rpx;
		position: relative;
	}

	.news .new-system-box .item .image .icon {
		width: 112rpx;
		height: 112rpx;
	}

	.news .new-system-box .item .image .img-tag {

		position: absolute;
		right: 0;
		top: -20rpx;

	}

	.news .new-system-box .item .right {
		display: flex;
		flex-direction: column;
		align-items: flex-start;
		justify-content: center;
		flex: 1;
		gap: 4rpx;
		height: 100%;
	}

	.news .new-system-box .item .right .title {
		width: 100%;
		display: flex;
		align-items: center;
		justify-content: space-between;
		color: #1e2331;
		font-weight: 500;
		font-size: 28rpx;
	}

	.news .new-system-box .item .right .title .time {
		color: #9b9fa8;
		font-weight: 400;
		font-size: 24rpx;
	}

	.news .new-system-box .item .right .news-content {
		color: #9b9fa8;
		font-weight: 400;
		font-size: 24rpx;
		max-width: 500rpx;
	}


	.subscribePup {}

	.subscribePup .loginBox {
		background-color: #fff;
		text-align: center;
		padding: 34rpx 0;
		height: 476rpx;
		border-radius: 30rpx 30rpx 0 0;
	}

	.subscribePup .loginBox .img {
		width: 340rpx;
		height: 340rpx;
	}

	.subscribePup .loginBox .loginBtn {
		width: 408rpx;
		margin: 0 auto;
		height: 80rpx;
		border-radius: 42rpx;
		background: #6acf69;
		color: #fff;
		font-size: 30rpx;
		font-weight: 500;
		line-height: 80rpx;
	}

	.subscribePup .loginBox .text {
		font-size: 20rpx;
		color: #999;
		text-align: center;
		margin-top: 16rpx;
	}

	// /deep/ .u-tabbar__content__item__text{
	// 		bottom: calc(28rpx + constant(safe-area-inset-bottom)) ;
	// 		bottom: calc(28rpx + env(safe-area-inset-bottom));
	// }
</style>